// src/App.js
import React from 'react';
import { BrowserRouter as Router } from 'react-router-dom';
import Navbar from './components/Navbar'; // Importa a Navbar
import Header from './components/Header'; // Importa o Header
import Dashboard from './components/Dashboard'; // Importa o Dashboard
import Calendar from './components/Calendar'; // Importa o Calendário

const App = () => {
  return (
    <Router>
      <div>
        <Navbar />  {/* Renderiza o componente de Navegação */}
        <Header />  {/* Renderiza o Header com os botões Pessoal e Escritório */}
        <Dashboard />  {/* Renderiza o Dashboard */}
        <Calendar />  {/* Renderiza o Calendário abaixo do Dashboard */}
      </div>
    </Router>
  );
};

export default App;
